import { Injectable, HttpException, HttpStatus } from '@nestjs/common';
import { HttpService } from '@nestjs/axios';
import { ConfigService } from '@nestjs/config';
import { firstValueFrom } from 'rxjs';
import { KybVerifyDto } from '../common/dto/kyb-verify.dto';
import { KybVerifyResponseDto } from '../common/dto/kyb-response.dto';

@Injectable()
export class KybService {
  private readonly apiKey: string;
  private readonly appId: string;
  private readonly baseUrl: string;
  private readonly sandbox: boolean;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
  ) {
    const premblyConfig = this.configService.get('prembly');
    this.apiKey = premblyConfig.apiKey;
    this.appId = premblyConfig.appId;
    this.baseUrl = premblyConfig.baseUrl;
    this.sandbox = premblyConfig.sandbox;
  }

  async verifyBusiness(dto: KybVerifyDto): Promise<KybVerifyResponseDto> {
    try {
      const endpoint = this.sandbox
        ? `${this.baseUrl}/sandbox/api/v1/biometrics/merchant/data/verification/kyc`
        : `${this.baseUrl}/api/v1/biometrics/merchant/data/verification/kyc`;

      const payload = {
        appid: this.appId,
        reference: this.generateReference(),
        customer_name: dto.businessRegistrationNumber,
        customer_type: dto.companyType,
        country: 'NG',
      };

      const response = await firstValueFrom(
        this.httpService.post(endpoint, payload, {
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${this.apiKey}`,
          },
        }),
      );

      return {
        success: true,
        message: 'Verification initiated successfully',
        data: response.data,
        reference: payload.reference,
        status: 'pending',
      };
    } catch (error) {
      if (error.response) {
        throw new HttpException(
          {
            success: false,
            message: error.response.data?.message || 'Verification failed',
            data: error.response.data,
          },
          error.response.status || HttpStatus.INTERNAL_SERVER_ERROR,
        );
      }
      throw new HttpException(
        {
          success: false,
          message: 'Internal server error',
        },
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
    }
  }

  private generateReference(): string {
    return `KYB-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }
}

