import * as crypto from 'crypto';

@Injectable()
export class WebhookService {
  private readonly webhookSecret: string;

  constructor(private readonly configService: ConfigService) {
    const premblyConfig = this.configService.get('prembly');
    this.webhookSecret = premblyConfig.webhookSecret;
  }

  /**
   * Verify the webhook signature
   * @param signature - The x-prembly-signature header value
   * @param payload - The raw request body as string
   * @returns true if signature is valid, throws BadRequestException otherwise
   */
  verifySignature(signature: string, payload: string): boolean {
    if (!signature) {
      throw new BadRequestException('Missing signature header');
    }

    // Remove 'sha256=' prefix if present
    const receivedSignature = signature.replace('sha256=', '');

    // Create HMAC using the webhook secret
    const hmac = crypto.createHmac('sha256', this.webhookSecret);
    hmac.update(payload);
    const calculatedSignature = hmac.digest('hex');

    // Compare signatures using timing-safe comparison
    if (!crypto.timingSafeEqual(Buffer.from(receivedSignature), Buffer.from(calculatedSignature))) {
      throw new BadRequestException('Invalid webhook signature');
    }

    return true;
  }

  /**
   * Process the webhook payload
   * @param payload - The webhook payload
   * @returns Processing result
   */
  async processWebhook(payload: any): Promise<{ success: boolean; message: string }> {
    // Extract relevant information from the webhook
    const { reference, status, data } = payload;

